INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
-- ═══ COPYWRITING (100 — pour TOUS les agents) ═══
('COPY: La formule 4U pour les titres: Utile + Urgent + Unique + Ultra-specifique. Ex: "5 clients en plus ce weekend (methode testee sur 200 restos)".', 'Formule 4U titres', NULL, 'best_practice', 0.92, 'massive_boost_5', 'system'),
('COPY: Les mots de pouvoir qui convertissent: gratuit, nouveau, garanti, prouve, exclusif, maintenant, decouvrez, secret, resultats.', 'Mots de pouvoir qui convertissent', NULL, 'best_practice', 0.90, 'massive_boost_5', 'system'),
('COPY: La formule "Meme si..." elimine les objections: "Gagnez 10 clients/mois, MEME SI vous n avez pas le temps de poster".', 'Formule meme si = eliminer objections', NULL, 'best_practice', 0.88, 'massive_boost_5', 'system'),
('COPY: Les bullets points avec benefice + specifique convertissent 2x mieux: "Gagnez 10h/semaine" > "Gagnez du temps".', 'Bullets specifiques = 2x conversion', NULL, 'best_practice', 0.90, 'massive_boost_5', 'system'),
('COPY: Le you-focus: utiliser "vous/tu" 2x plus que "je/nous" dans le copy. Le lecteur veut lire sur LUI pas sur VOUS.', 'You-focus: 2x plus vous/tu que je/nous', NULL, 'best_practice', 0.92, 'massive_boost_5', 'system'),
('COPY: La technique du bucket brigade (mots de transition qui gardent le lecteur): "Mais attendez...", "Voila pourquoi...", "Le secret ?".', 'Bucket brigade = garder le lecteur', NULL, 'best_practice', 0.85, 'massive_boost_5', 'system'),
('COPY: Le principe KISS (Keep It Simple Stupid): ecrire pour un niveau de lecture de 12 ans. Phrases courtes. Mots simples.', 'KISS: ecrire simple, phrases courtes', NULL, 'best_practice', 0.92, 'massive_boost_5', 'system'),
('COPY: Les chiffres impairs sont percus comme plus credibles: "7 astuces" > "6 astuces" ou "8 astuces".', 'Chiffres impairs = plus credibles', NULL, 'insight', 0.82, 'massive_boost_5', 'system'),
('COPY: Le CTA negatif ("Ne ratez pas cette opportunite") convertit 15% mieux que le positif ("Profitez de cette opportunite") grace au loss aversion.', 'CTA negatif > positif: +15% (loss aversion)', NULL, 'insight', 0.85, 'massive_boost_5', 'system'),
('COPY: Commencer par le resultat, pas le processus. "10 clients en plus" avant "notre methode en 3 etapes". Le benefice d abord.', 'Resultat d abord, processus ensuite', NULL, 'best_practice', 0.92, 'massive_boost_5', 'system'),
('COPY: L utilisation de la voix active (nous faisons > il est fait) augmente la clarte et la conversion de 25%.', 'Voix active = +25% conversion', NULL, 'best_practice', 0.88, 'massive_boost_5', 'system'),
('COPY: Le suspense (ne pas tout reveler dans le titre) augmente le CTR de 30%. "Ce que 90% des restos font mal..." > "5 erreurs marketing".', 'Suspense titre = +30% CTR', NULL, 'insight', 0.85, 'massive_boost_5', 'system'),

-- ═══ ANALYTICS / DATA (60 — pour CEO + Marketing) ═══
('ANALYTICS: Le taux de rebond moyen acceptable: landing page < 40%, blog < 60%, e-commerce < 30%. Au-dessus = probleme d experience.', 'Bounce rate benchmarks par type', NULL, 'insight', 0.90, 'massive_boost_5', 'system'),
('ANALYTICS: Le temps moyen sur page pour un article qui convertit: > 3 minutes. En dessous, le contenu ne retient pas.', 'Temps page > 3 min pour convertir', NULL, 'insight', 0.88, 'massive_boost_5', 'system'),
('ANALYTICS: Le taux de conversion moyen par canal: SEO 2.4%, Paid Search 1.5%, Social 0.7%, Email 3.9%, Referral 3.2%.', 'Conversion par canal: email > SEO > referral > paid > social', NULL, 'insight', 0.88, 'massive_boost_5', 'system'),
('ANALYTICS: Les UTM parameters sont obligatoires pour tracker chaque campagne. Format: utm_source, utm_medium, utm_campaign, utm_content.', 'UTM parameters obligatoires tracking', NULL, 'best_practice', 0.93, 'massive_boost_5', 'system'),
('ANALYTICS: Le modele d attribution last-click sous-evalue les canaux de decouverte (social, content). Utiliser un modele multi-touch.', 'Attribution multi-touch > last-click', NULL, 'best_practice', 0.88, 'massive_boost_5', 'system'),
('ANALYTICS: Le cohort retention chart est le meilleur outil pour comprendre le churn. Si la courbe ne se stabilise pas, le produit a un probleme.', 'Cohort retention: courbe doit se stabiliser', NULL, 'insight', 0.90, 'massive_boost_5', 'system'),
('ANALYTICS: Le DAU/MAU ratio (Daily Active Users / Monthly Active Users) mesure la stickiness. > 20% = bon. > 40% = excellent.', 'DAU/MAU: > 20% bon, > 40% excellent', NULL, 'insight', 0.85, 'massive_boost_5', 'system'),
('ANALYTICS: Le feature adoption rate doit etre suivi par feature. Si < 5% des users utilisent une feature, elle est peut-etre mal decouverte.', 'Feature adoption < 5% = mal decouverte', NULL, 'insight', 0.85, 'massive_boost_5', 'system'),

